/**
 * Notification model types.
 *
 * These types define the structure of notifications flowing through the system.
 * All notification channels (email, webhook, SMS, etc.) use these shared types.
 */

/**
 * Supported notification types — each maps to a distinct template/format.
 */
export type NotificationType =
  | 'order_confirmation'
  | 'order_status_update'
  | 'welcome'
  | 'account_updated';

/**
 * Delivery channels for notifications.
 */
export type NotificationChannel = 'email' | 'webhook' | 'sms' | 'in_app';

/**
 * The payload passed to notification adapters for rendering and delivery.
 */
export interface NotificationPayload {
  type: NotificationType;
  recipient: string;
  subject: string;
  body: string;
  metadata?: Record<string, unknown>;
}

/**
 * Result returned by a notification adapter after attempting delivery.
 */
export interface NotificationResult {
  success: boolean;
  channel: NotificationChannel;
  recipient: string;
  /** Adapter-specific identifier for the sent notification (e.g., message ID). */
  messageId?: string;
  error?: string;
}

/**
 * A persisted notification record.
 */
export interface Notification {
  id: string;
  type: NotificationType;
  channel: NotificationChannel;
  recipient: string;
  subject: string;
  body: string;
  sentAt: Date;
  success: boolean;
  error?: string;
}

/**
 * NotificationAdapter interface — the contract all notification channels must implement.
 *
 * Architecture constraint: Every notification channel (email, webhook, SMS, in-app)
 * must implement this interface. The NotificationService routes payloads to adapters;
 * adapters handle channel-specific rendering and delivery.
 *
 * Adapters MUST NOT subscribe to EventBus directly. Only NotificationService
 * subscribes to events and delegates to adapters.
 */

import type { NotificationChannel, NotificationPayload, NotificationResult } from '../models/notification.js';

export interface NotificationAdapter {
  /** The channel this adapter handles. */
  readonly channel: NotificationChannel;

  /**
   * Send a notification through this channel.
   * Must return a result indicating success or failure — must not throw.
   */
  send(payload: NotificationPayload): Promise<NotificationResult>;
}

/**
 * Email notification adapter.
 *
 * Implements NotificationAdapter for the email channel. Currently a stub
 * that logs sends in-memory. Replace the send() internals with a real
 * email provider (SES, SendGrid, SMTP, etc.) for production use.
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type { NotificationChannel, NotificationPayload, NotificationResult } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

export class EmailNotificationAdapter implements NotificationAdapter {
  readonly channel: NotificationChannel = 'email';
  private logger = new Logger('EmailAdapter');
  private sent: Array<{ payload: NotificationPayload; timestamp: Date }> = [];

  async send(payload: NotificationPayload): Promise<NotificationResult> {
    this.logger.info(`Sending email to ${payload.recipient}: ${payload.subject}`);

    // Stub: in production, call an email provider here.
    this.sent.push({ payload, timestamp: new Date() });

    return {
      success: true,
      channel: this.channel,
      recipient: payload.recipient,
      messageId: `email-${Date.now()}`,
    };
  }

  /** Get all sent emails. Useful for testing. */
  getSentEmails(): Array<{ payload: NotificationPayload; timestamp: Date }> {
    return [...this.sent];
  }

  /** Clear sent emails. Useful for testing. */
  clearSentEmails(): void {
    this.sent = [];
  }
}

/**
 * Notification service — the central hub for all notification delivery.
 *
 * Architecture: Event-driven, single pattern.
 * - Subscribes to events on the EventBus
 * - Translates events into NotificationPayloads
 * - Routes payloads to registered NotificationAdapter implementations
 *
 * Constraints:
 * - This service is the SOLE subscriber for notification concerns.
 *   Individual adapters must NOT subscribe to EventBus directly.
 * - All notification channels must implement the NotificationAdapter interface.
 * - New event types require adding a handler here and a corresponding
 *   NotificationType in models/notification.ts.
 */

import type { EventBus } from '../events/event-bus.js';
import type {
  OrderCreatedEvent,
  OrderStatusChangedEvent,
  UserCreatedEvent,
  UserUpdatedEvent,
} from '../events/event-types.js';
import type { NotificationAdapter } from '../adapters/notification.adapter.js';
import type {
  Notification,
  NotificationChannel,
  NotificationPayload,
  NotificationType,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generateNotificationId(): string {
  return `notif-${String(nextId++).padStart(4, '0')}`;
}

export function resetNotificationIdCounter(): void {
  nextId = 1;
}

export class NotificationService {
  private logger = new Logger('NotificationService');
  private notifications: Notification[] = [];
  private adapters: Map<NotificationChannel, NotificationAdapter> = new Map();

  constructor(private eventBus: EventBus) {
    this.registerEventHandlers();
  }

  /**
   * Register a notification adapter for a channel.
   * Only one adapter per channel — last registration wins.
   */
  registerAdapter(adapter: NotificationAdapter): void {
    this.logger.info(`Registered adapter for channel: ${adapter.channel}`);
    this.adapters.set(adapter.channel, adapter);
  }

  /**
   * Subscribe to all notification-triggering events on the EventBus.
   */
  private registerEventHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) =>
      this.handleOrderCreated(event),
    );

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) =>
      this.handleOrderStatusChanged(event),
    );

    this.eventBus.on<UserCreatedEvent>('user:created', (event) =>
      this.handleUserCreated(event),
    );

    this.eventBus.on<UserUpdatedEvent>('user:updated', (event) =>
      this.handleUserUpdated(event),
    );
  }

  private async handleOrderCreated(event: OrderCreatedEvent): Promise<void> {
    const itemSummary = event.order.items
      .map((item) => `${item.name} x${item.quantity}`)
      .join(', ');

    await this.send({
      type: 'order_confirmation',
      recipient: event.user.email,
      subject: `Order Confirmation: ${event.order.id}`,
      body: `Your order has been placed. Items: ${itemSummary}. Total: $${event.order.total.toFixed(2)}`,
      metadata: { orderId: event.order.id, userId: event.user.id },
    });
  }

  private async handleOrderStatusChanged(event: OrderStatusChangedEvent): Promise<void> {
    await this.send({
      type: 'order_status_update',
      recipient: event.order.userId,
      subject: `Order Update: ${event.order.id}`,
      body: `Your order status has changed from ${event.previousStatus} to ${event.newStatus}.`,
      metadata: {
        orderId: event.order.id,
        previousStatus: event.previousStatus,
        newStatus: event.newStatus,
      },
    });
  }

  private async handleUserCreated(event: UserCreatedEvent): Promise<void> {
    await this.send({
      type: 'welcome',
      recipient: event.user.email,
      subject: 'Welcome to TaskFlow Pro',
      body: `Welcome, ${event.user.name}! Your account has been created.`,
      metadata: { userId: event.user.id },
    });
  }

  private async handleUserUpdated(event: UserUpdatedEvent): Promise<void> {
    await this.send({
      type: 'account_updated',
      recipient: event.user.email,
      subject: 'Account Updated',
      body: `Your account has been updated. Changed fields: ${event.changes.join(', ')}.`,
      metadata: { userId: event.user.id, changes: event.changes },
    });
  }

  /**
   * Send a notification through all registered adapters.
   * Each adapter attempts delivery independently — one failure does not block others.
   */
  async send(payload: NotificationPayload): Promise<Notification[]> {
    this.logger.info(`Sending ${payload.type} notification to ${payload.recipient}`);

    if (this.adapters.size === 0) {
      this.logger.warn('No adapters registered — notification will only be recorded in-memory');
    }

    const results: Notification[] = [];

    for (const adapter of this.adapters.values()) {
      const result = await adapter.send(payload);
      const record: Notification = {
        id: generateNotificationId(),
        type: payload.type,
        channel: adapter.channel,
        recipient: payload.recipient,
        subject: payload.subject,
        body: payload.body,
        sentAt: new Date(),
        success: result.success,
        error: result.error,
      };
      this.notifications.push(record);
      results.push(record);
    }

    // If no adapters, still record for in-memory tracking
    if (this.adapters.size === 0) {
      const record: Notification = {
        id: generateNotificationId(),
        type: payload.type,
        channel: 'in_app',
        recipient: payload.recipient,
        subject: payload.subject,
        body: payload.body,
        sentAt: new Date(),
        success: true,
      };
      this.notifications.push(record);
      results.push(record);
    }

    return results;
  }

  /** Get all notification records. */
  getNotifications(): Notification[] {
    return [...this.notifications];
  }

  /** Get notifications for a specific recipient. */
  getNotificationsForRecipient(recipient: string): Notification[] {
    return this.notifications.filter((n) => n.recipient === recipient);
  }

  /** Get notifications by type. */
  getNotificationsByType(type: NotificationType): Notification[] {
    return this.notifications.filter((n) => n.type === type);
  }

  /** Get the count of sent notifications. */
  getNotificationCount(): number {
    return this.notifications.length;
  }

  /** Clear all notification records. Useful for testing. */
  clearNotifications(): void {
    this.notifications = [];
  }
}

/**
 * Notification service — the central hub for all notification delivery.
 *
 * Architecture: Event-driven, single pattern (EventBus only).
 * - Subscribes to events on the EventBus
 * - Translates events into NotificationPayloads
 * - Routes payloads to registered NotificationAdapter implementations
 *
 * Constraints:
 * - This service is the SOLE subscriber for notification concerns.
 *   Individual adapters must NOT subscribe to EventBus directly.
 * - All notification channels must implement the NotificationAdapter interface.
 * - New event types require adding a handler here and a corresponding
 *   NotificationType in models/notification.ts.
 */

import type { EventBus } from '../events/event-bus.js';
import type {
  OrderCreatedEvent,
  OrderStatusChangedEvent,
  UserCreatedEvent,
  UserUpdatedEvent,
} from '../events/event-types.js';
import type { NotificationAdapter } from '../adapters/notification.adapter.js';
import type {
  Notification,
